mapper.select:
SELECT t3.* FROM sys_user_role AS t1 LEFT JOIN sys_role_function AS t2 ON t1.role_id = t2.role_id LEFT JOIN sys_function AS t3 ON t3.function_id = t2.function_id WHERE t3.function_id IS NOT NULL
AND t1.user_id = #{userId}
AND t2.role_id = #{roleId}
GROUP BY t3.function_id ORDER BY function_pid ASC, sort ASC
